      url: "https://mcp.example.com/sse",
      headers: { Authorization: "Bearer my-token" },
    },
  ],
});
```

<Aside type="note">
**Pre-install `npx`-launched servers.** A local server started with `npx -y …` writes install progress to **stdout** on its first run, which corrupts the MCP stdio handshake (you'll see `Connection closed`). Pre-install it in the VM so `npx` is silent — `await agent.exec("npm install -g @modelcontextprotocol/server-filesystem")` before the session — or pin the package and point `command` at the installed binary.
</Aside>

## Extensions

Pi supports [extensions](https://github.com/badlogic/pi-mono/tree/main/packages/coding-agent/examples/extensions) that let you register custom tools, modify the system prompt, and hook into agent lifecycle events. Write a `.js` file into the VM's extensions directory before creating a session and Pi discovers it automatically.

Pi scans two directories for `.js` extension files:

| Directory | Scope |
|-----------|-------|
| `~/.pi/agent/extensions/` | Global — applies to all Pi sessions |
| `<cwd>/.pi/extensions/` | Project — applies only when cwd matches |

```ts
const extensionCode = `
export default function(pi) {
  // Modify the system prompt before each agent turn
  pi.on("before_agent_start", async (event) => {
    return {
      systemPrompt: event.systemPrompt +
        "\\n\\nAlways respond in formal English."
    };
  });
}
`;

// Write the extension before creating the session
await agent.mkdir("/home/agentos/.pi/agent/extensions", { recursive: true });
await agent.writeFile("/home/agentos/.pi/agent/extensions/formal.js", extensionCode);

// Pi discovers the extension automatically
const { sessionId } = await agent.createSession("pi", {
  env: { ANTHROPIC_API_KEY: process.env.ANTHROPIC_API_KEY },
});
```

See the [Pi extension documentation](https://github.com/badlogic/pi-mono/tree/main/packages/coding-agent/examples/extensions) for the full extension API.

## Customizing the agent

Pi is a built-in agent, but it's just a software package under the hood. To ship your own ACP adapter, swap the underlying agent SDK, or register a tweaked Pi build as a new agent, see [Custom Agents](/docs/agents/custom).

import { Aside } from '@astrojs/starlight/components';

A custom agent is a program that runs **inside the VM** to drive a coding agent. agentOS spawns it when you call `createSession()` and talks to it over the Agent Client Protocol. You ship it as a software package, exactly like the built-in agents.

## Agent Client Protocol (ACP)

agentOS speaks the [Agent Client Protocol (ACP)](https://agentclientprotocol.com) to every agent: JSON-RPC over stdio. The agent reads protocol messages on **stdin** and writes them on **stdout**, so stdout is reserved for ACP and **stderr is used for logs**. Your program only needs to speak ACP; how it runs the underlying model is up to you. See the [ACP documentation](https://agentclientprotocol.com) for the full protocol.

## Two ways to build an agent

There are two shapes, depending on whether the agent runs in the ACP process or in its own.

### Single process (embedded)

The ACP adapter **embeds the agent SDK** and runs it in the same process. One process inside the VM, lower memory footprint.

